import{_ as i,o as a,c as t,ag as l}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Aliasuri AI | Dotfiles (RO)","titleTemplate":":title","description":"Comenzi scurte pentru AI. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","frontmatter":{"title":"Aliasuri AI | Dotfiles","description":"Comenzi scurte pentru AI. Prezentare generală pentru Dotfiles v0.2.495. Compatibil cu macOS, Linux și WSL prin Dotfiles.","lang":"ro-RO","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasuri AI | Previzualizare Dotfiles","canonical":"/ro/aliases/ai/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasuri AI","pageType":"docs","schemaType":"WebPage","permalink":"/ro/aliases/ai/"},"headers":[],"relativePath":"ro/aliases/ai/index.md","filePath":"ro/aliases/ai/index.md","lastUpdated":1773010926000}'),o={name:"ro/aliases/ai/index.md"};function d(c,e,r,n,s,u){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="aliasuri-ai" tabindex="-1">Aliasuri AI <a class="header-anchor" href="#aliasuri-ai" aria-label="Permalink to &quot;Aliasuri AI&quot;">​</a></h1><p>Comenzi scurte pentru instrumente AI.</p><p>Această pagină prezintă un grup de aliasuri și scurtăturile sale de comandă obișnuite. Citiți-o mai întâi pentru a înțelege convențiile de denumire, intrările așteptate și tiparele de execuție sigure. Apoi deschideți anexa de referință pentru inventarul complet de comenzi și sintaxa exactă. Aceste aliasuri reduc tastarea repetitivă și mențin un comportament consistent pe macOS, Linux și WSL.</p><h2 id="cand-se-utilizeaza" tabindex="-1">Când se utilizează <a class="header-anchor" href="#cand-se-utilizeaza" aria-label="Permalink to &quot;Când se utilizează&quot;">​</a></h2><p>Utilizați această pagină înainte de lucrul zilnic în shell când aveți nevoie de tipare de comandă previzibile.</p><h2 id="ce-este-inclus" tabindex="-1">Ce este inclus <a class="header-anchor" href="#ce-este-inclus" aria-label="Permalink to &quot;Ce este inclus&quot;">​</a></h2><ul><li>Aliasuri: 46</li><li>Funcții helper: 0</li><li>Fișiere sursă: 1</li></ul><h2 id="exemple-rapide" tabindex="-1">Exemple rapide <a class="header-anchor" href="#exemple-rapide" aria-label="Permalink to &quot;Exemple rapide&quot;">​</a></h2><ul><li><code>a</code> → <code>ai_core query</code></li><li><code>ai</code> → <code>sgpt</code></li><li><code>aic</code> → <code>sgpt --code</code></li><li><code>aid</code> → <code>aider --read ~/.config/ai/identity.md</code></li><li><code>aida</code> → <code>aider --read ~/.config/ai/identity.md --chat-mode ask</code></li><li><code>aidc</code> → <code>aider --read ~/.config/ai/identity.md --chat-mode code</code></li><li><code>aidw</code> → <code>aider --read ~/.config/ai/identity.md --watch-files</code></li><li><code>aie</code> → <code>sgpt --shell</code></li><li><code>cl</code> → <code>claude</code></li><li><code>clc</code> → <code>claude --chat</code></li><li><code>clp</code> → <code>claude &lt; ~/.config/ai/identity.md</code></li><li><code>cod</code> → <code>codex</code></li></ul><h2 id="pasul-urmator" tabindex="-1">Pasul următor <a class="header-anchor" href="#pasul-urmator" aria-label="Permalink to &quot;Pasul următor&quot;">​</a></h2><p>Deschideți lista completă:</p>',11)])])}const h=i(o,[["render",d]]);export{m as __pageData,h as default};
